import{_ as s,o as a,c as e,a as n}from"./app.7722c78a.js";const m=JSON.parse('{"title":"Summary","description":"","frontmatter":{},"headers":[{"level":2,"title":"Code 语法","slug":"code-语法","link":"#code-语法","children":[]},{"level":2,"title":"Node 语法","slug":"node-语法","link":"#node-语法","children":[]},{"level":2,"title":"拒绝交叉","slug":"拒绝交叉","link":"#拒绝交叉","children":[]},{"level":2,"title":"PHP 方式","slug":"php-方式","link":"#php-方式","children":[]},{"level":2,"title":"扩展支持","slug":"扩展支持","link":"#扩展支持","children":[]}],"relativePath":"docs/template/index.md"}'),l={name:"docs/template/index.md"},p=n(`<h1 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary">¶</a></h1><div class="tip custom-block"><p class="custom-block-title">Testing Is Documentation</p><p><a href="https://github.com/hunzhiwange/framework/blob/master/tests/View/SummaryDoc.php" target="_blank" rel="noreferrer">tests/View/SummaryDoc.php</a></p></div><p>QueryPHP 内置二种方式的模板引擎，一种是类似于 Smart 模板的 Code 语法，一种是 HTML 标签式的 Node 语法。</p><ul><li>code 语法，侧重简单实用，输出变量、注释等</li><li>Node 语法，严谨务实，输出循环、流程控制等</li></ul><p>例外，二种语法随心嵌套，随意使用，QueryPHP 模板引擎底层分析器和编译器非常健壮，完美运行 10 年。</p><p>QueryPHP 模板引擎技术来自于 Jecat,一款无与伦比的技术大餐，有幸在 2010 接触到这个框架，通过这个框架学到了很多。</p><h2 id="code-语法" tabindex="-1">Code 语法 <a class="header-anchor" href="#code-语法">¶</a></h2><p>侧重简单实用。</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{{ $name }}</span></span>
<span class="line"></span></code></pre></div><h2 id="node-语法" tabindex="-1">Node 语法 <a class="header-anchor" href="#node-语法">¶</a></h2><p>严谨务实。</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{% if cond=&quot;&#39;You&#39; == $name&quot; %}</span></span>
<span class="line"><span style="color:#A6ACCD;">    欢迎进入 QueryPHP 开发者世界！</span></span>
<span class="line"><span style="color:#A6ACCD;">{% :if %}</span></span>
<span class="line"></span></code></pre></div><h2 id="拒绝交叉" tabindex="-1">拒绝交叉 <a class="header-anchor" href="#拒绝交叉">¶</a></h2><p>下面这种写法就是错误的，模板引擎将无法正确解析。</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{% $name %}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">{{ if cond=&quot;&#39;You&#39; == $name&quot; }}</span></span>
<span class="line"><span style="color:#A6ACCD;">    欢迎进入 QueryPHP 开发者世界！</span></span>
<span class="line"><span style="color:#A6ACCD;">{{ :if }}</span></span>
<span class="line"></span></code></pre></div><h2 id="php-方式" tabindex="-1">PHP 方式 <a class="header-anchor" href="#php-方式">¶</a></h2><p>如果你不习惯使用使用内置的模板引擎，你也可以完全使用 PHP 自生来写。</p><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;?</span><span style="color:#A6ACCD;">php </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">You</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">==</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">$</span><span style="color:#A6ACCD;">name</span><span style="color:#89DDFF;">):</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">?&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    欢迎进入 QueryPHP 开发者世界！</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;?</span><span style="color:#A6ACCD;">php </span><span style="color:#89DDFF;font-style:italic;">endif</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">?&gt;</span></span>
<span class="line"></span></code></pre></div><h2 id="扩展支持" tabindex="-1">扩展支持 <a class="header-anchor" href="#扩展支持">¶</a></h2><p>为了减少学习成本，系统还支持 PHP 自身作为 UI 模板。</p>`,20),o=[p];function t(c,i,r,d,h,y){return a(),e("div",null,o)}const u=s(l,[["render",t]]);export{m as __pageData,u as default};
